from flask import Flask, request, jsonify

LOG_FILE = os.environ.get("WEBAPP_LOG_FILE", "webapp.log")
LOG_LEVEL = os.environ.get("WEBAPP_LOG_LEVEL", "INFO").upper()
MAX_BYTES = int(os.environ.get("WEBAPP_LOG_MAX_BYTES", 10 * 1024 * 1024))
BACKUP_COUNT = int(os.environ.get("WEBAPP_LOG_BACKUP_COUNT", 5))
HOST = os.environ.get("WEBAPP_LOG_HOST", "0.0.0.0")
